/* PLL 配置：HSE 25MHz -> 480MHz SYSCLK */
typedef struct {
    uint32_t PLLM;    /* 输入分频 */
    uint32_t PLLN;    /* 倍频系数 */
    uint32_t PLLP;    /* 系统时钟分频 */
    uint32_t PLLQ;    /* USB/SAI 时钟分频 */
    uint32_t PLLR;    /* 可选输出分频 */
} PLL_Config_t;

