    .PLLP = 2,    /* 960MHz / 2 = 480MHz SYSCLK */
    .PLLQ = 20,   /* 960MHz / 20 = 48MHz  (USB) */
    .PLLR = 2     /* 960MHz / 2 = 480MHz (备用) */
};

