#include "dma.h"
#include "spi.h"

#define SPI_DMA_BUF_SIZE  512

/* DMA 传输句柄 */
typedef struct {
    uint8_t  tx_buf[SPI_DMA_BUF_SIZE];
    uint8_t  rx_buf[SPI_DMA_BUF_SIZE];
    uint16_t transfer_size;
    volatile uint8_t done;
} SPI_DMA_Handle_t;

static SPI_DMA_Handle_t spi_dma;

/**
 * 初始化 SPI + DMA（双缓冲乒乓模式）
 */
void spi_dma_init(void)
{
    /* 1. 使能 DMA 时钟 */
    RCC->AHB1ENR |= RCC_AHB1ENR_DMA2EN;

    /* 2. 配置 DMA 流 */
    DMA_Stream_TypeDef *dma_tx = DMA2_Stream3;  /* SPI1 TX */
    DMA_Stream_TypeDef *dma_rx = DMA2_Stream2;  /* SPI1 RX */

    /* TX 配置 */
    dma_tx->CR = 0;
    dma_tx->CR |= (0x03 << DMA_SxCR_CHSEL_Pos);  /* 通道 3 */
    dma_tx->CR |= DMA_SxCR_DIR_0;                 /* 内存->外设 */
    dma_tx->CR |= DMA_SxCR_MINC;                  /* 内存地址递增 */
    dma_tx->CR |= DMA_SxCR_TCIE;                  /* 传输完成中断 */
    dma_tx->PAR  = (uint32_t)&SPI1->DR;           /* 外设地址 */

    /* RX 配置 */
    dma_rx->CR = 0;
    dma_rx->CR |= (0x03 << DMA_SxCR_CHSEL_Pos);
    dma_rx->CR &= ~DMA_SxCR_DIR_0;                 /* 外设->内存 */
    dma_rx->CR |= DMA_SxCR_MINC;
    dma_rx->CR |= DMA_SxCR_TCIE;
    dma_rx->PAR  = (uint32_t)&SPI1->DR;

    /* 3. 使能 SPI DMA 请求 */
    SPI1->CR2 |= SPI_CR2_TXDMAEN | SPI_CR2_RXDMAEN;

    /* 4. 配置 NVIC */
    NVIC_SetPriority(DMA2_Stream3_IRQn, 6);
    NVIC_EnableIRQ(DMA2_Stream3_IRQn);

    printf("[DMA] SPI DMA initialized (dual-buffer mode)\n");
}

/**
 * 启动 DMA 传输
 */
void spi_dma_transfer(const uint8_t *tx_data, uint8_t *rx_data, uint16_t size)
{
    spi_dma.done = 0;

    /* 设置内存地址 */
    DMA2_Stream3->M0AR = (uint32_t)tx_data;
    DMA2_Stream2->M0AR = (uint32_t)rx_data;

    /* 设置传输大小 */
    DMA2_Stream3->NDTR = size;
    DMA2_Stream2->NDTR = size;

    /* 使能 DMA 流 */
    DMA2_Stream3->CR |= DMA_SxCR_EN;
    DMA2_Stream2->CR |= DMA_SxCR_EN;

    printf("[DMA] Transfer started: %u bytes\n", size);
}

/* DMA 完成中断 */
void DMA2_Stream3_IRQHandler(void)
{
    if (DMA2->LISR & DMA_LISR_TCIF3) {
        DMA2->LIFCR |= DMA_LIFCR_CTCIF3;  /* 清除标志 */
        spi_dma.done = 1;
        printf("[DMA] Transfer complete\n");
    }
}

#include "power.h"

/**
 * 进入 Stop 模式（RTC 定时唤醒）
 */
void enter_stop_mode(uint32_t wakeup_sec)
{
    printf("[PM] Entering Stop mode for %lu seconds...\n", wakeup_sec);

    /* 1. 挂起 SysTick（防止意外唤醒） */
    SysTick->CTRL &= ~SysTick_CTRL_ENABLE_MASK;

    /* 2. 配置 RTC 唤醒定时器 */
    rtc_set_wakeup_timer(wakeup_sec);

    /* 3. 关闭不必要的外设 */
    power_peripheral_off(PERIPH_USB);
    power_peripheral_off(PERIPH_SDIO);

    /* 4. 配置唤醒源 */
    PWR->CR |= PWR_CR_CWUF;          /* 清除唤醒标志 */
    PWR->CSR1 |= PWR_CSR1_WUPEN1;    /* 启用 WKUP1 引脚 */

    /* 5. 进入 STOP 模式 */
    HAL_PWR_EnterSTOPMode(PWR_LOWPOWERREGULATOR_ON, PWR_STOPENTRY_WFI);

    /* 6. 唤醒后 — 恢复系统 */
    SystemClock_Config();            /* 重新配置时钟 */
    SysTick->CTRL |= SysTick_CTRL_ENABLE_MASK;

    printf("[PM] Woke up from Stop mode\n");
    printf("[PM] Sleep duration: %lu seconds\n", rtc_get_sleep_duration());
}

/**
 * 根据电池电量自动切换省电策略
 */
typedef enum {
    PM_PROFILE_PERFORMANCE,  /* >80% 电量 — 全速 */
    PM_PROFILE_BALANCED,     /* 50-80% — 降频 */
    PM_PROFILE_POWERSAVE,    /* 20-50% — 间歇休眠 */
    PM_PROFILE_CRITICAL      /* <20% — 极限省电 */
} pm_profile_t;

pm_profile_t pm_auto_select(void)
{
    float battery = adc_read_battery_voltage();
    float percent = (battery - 3.0f) / (4.2f - 3.0f) * 100.0f;

    if (percent > 80.0f) return PM_PROFILE_PERFORMANCE;
    if (percent > 50.0f) return PM_PROFILE_BALANCED;
    if (percent > 20.0f) return PM_PROFILE_POWERSAVE;
    return PM_PROFILE_CRITICAL;
}

#include "FreeRTOS.h"
#include "task.h"
#include "queue.h"
#include "semphr.h"

/* 任务句柄 */
static TaskHandle_t  hBreathTask  = NULL;
static TaskHandle_t  hButtonTask  = NULL;
static TaskHandle_t  hMonitorTask = NULL;

/* 队列 — 传递按键事件 */
static QueueHandle_t xButtonQueue;

/* 互斥锁 — 保护 PWM 硬件 */
static SemaphoreHandle_t xPWMMutex;

void app_main(void)
{
    /* 创建队列 */
    xButtonQueue = xQueueCreate(8, sizeof(uint8_t));
    xPWMMutex    = xSemaphoreCreateMutex();

    /* 创建任务 */
    xTaskCreate(vBreathTask,  "Breath",  512, NULL,
                TASK_PRIO_NORMAL, &hBreathTask);
    xTaskCreate(vButtonTask,  "Button",  256, NULL,
                TASK_PRIO_HIGH,   &hButtonTask);
    xTaskCreate(vMonitorTask, "Monitor", 384, NULL,
                TASK_PRIO_LOW,    &hMonitorTask);

    /* 启动调度器 */
    vTaskStartScheduler();

    /* 不应到达这里 */
    while (1);
}

/* 呼吸灯任务 */
void vBreathTask(void *pvParams)
{
    uint32_t duty = 0;
    uint8_t  dir  = 1;

    for (;;) {
        if (xSemaphoreTake(xPWMMutex, pdMS_TO_TICKS(10)) == pdTRUE) {
            timer_pwm_set_duty(TIM2, 1, duty);
            xSemaphoreGive(xPWMMutex);
        }

        duty += dir ? 10 : -10;
        if (duty >= PWM_PERIOD) dir = 0;
        if (duty == 0)          dir = 1;

        vTaskDelay(pdMS_TO_TICKS(15));
    }
}
